import React from "react";
import { motion } from "framer-motion";
import Badges from "./Badges";
import Github from "./Github";
import Leetcode from "./Leetcode";
import Techstack from "./Techstack";
import Toolstack from "./Toolstack";
import Tilt from "react-parallax-tilt";
import awardImg from "../../assets/award.jpg";

function About() {
    return (
        <section id="about" className="relative z-10 w-full min-h-screen py-20">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

                {/* About Me Section */}
                <div className="flex flex-col md:flex-row items-center justify-between gap-12 mb-24">

                    <motion.div
                        className="w-full md:w-3/5 text-center md:text-left"
                        initial={{ opacity: 0, x: -50 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.8 }}
                    >
                        <h1 className="text-4xl md:text-5xl font-bold mb-8">
                            Know Who <strong className="text-primary-purple">I'm</strong>
                        </h1>
                        <div className="text-lg text-gray-300 leading-relaxed max-w-2xl space-y-4">
                            <p>
                                Hi Everyone, I am <span className="text-primary-purple font-semibold">Akanksha Kumari</span>
                                .
                            </p>
                            <p>
                                I am currently pursuing my BTech in Computer Science from Lakshmi Narain College of Technology Excellence (Expected Graduation 2027).
                            </p>
                            <p>
                                I am passionate about building full-stack applications, solving complex algorithms, and integrating AI functionality into intuitive user interfaces. I've actively solved over 400+ problems across LeetCode, GFG, and Codeforces, and love participating in hackathons to push the limits of my skills.
                            </p>
                            <br />
                            <p className="text-primary-purple italic font-serif opacity-80 border-l-4 border-primary-purple pl-4">
                                "Striving to build elegant and functional software that makes an impact."
                            </p>
                        </div>
                    </motion.div>

                    <motion.div
                        className="w-full md:w-2/5 flex justify-center mt-12 md:mt-0"
                        initial={{ opacity: 0, x: 50 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.8, delay: 0.2 }}
                    >
                        <Tilt className="w-full max-w-sm">
                            <div className="relative w-72 h-72 md:w-80 md:h-80 mx-auto rounded-2xl overflow-hidden glass flex items-center justify-center p-2 transform rotate-3 border-2 border-primary-purple/30 shadow-[0_0_40px_rgba(199,112,240,0.4)]">
                                <img
                                    src={awardImg}
                                    alt="First Prize Award LNCT"
                                    className="w-full h-full object-cover rounded-xl"
                                />
                            </div>
                        </Tilt>
                    </motion.div>
                </div>

                {/* Skillset Sections */}
                <div className="mt-12">
                    <h1 className="text-3xl md:text-4xl font-bold text-center mb-12">
                        Professional <strong className="text-primary-purple">Skillset</strong>
                    </h1>
                    <Techstack />
                </div>

                <div className="mt-16">
                    <h1 className="text-3xl md:text-4xl font-bold text-center mb-12">
                        <strong className="text-primary-purple">Tools</strong> I use
                    </h1>
                    <Toolstack />
                </div>

                {/* Activity Calendars */}
                <div className="mt-20 flex flex-col gap-16 justify-center items-center w-full">
                    <div className="w-full">
                        <Github />
                    </div>
                    <div className="w-full">
                        <Leetcode />
                    </div>
                </div>

                {/* Achivement Badges */}
                <Badges />

            </div>
        </section>
    );
}

export default About;

import React from "react";
import { motion } from "framer-motion";
import badgesData from "./leetcode_badges.json";
import gssocImg from "../../assets/badges/gssoc.jpg";

function Badges() {
    const badges = [
        ...badgesData.data.matchedUser.badges,
        {
            displayName: "GSSoC Contributor Badge",
            icon: gssocImg
        }
    ];

    return (
        <motion.div
            initial={{ opacity: 0, y: 50 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8, delay: 0.3 }}
            className="flex flex-col items-center justify-center pt-20 pb-12 w-full"
        >
            <h2 className="text-3xl md:text-4xl font-bold mb-10 text-center">
                My <strong className="text-primary-purple">Achievements</strong>
            </h2>
            <div className="flex flex-wrap justify-center gap-6 md:gap-8 w-full max-w-5xl">
                {badges.map((badge, index) => (
                    <motion.div
                        key={index}
                        whileHover={{ scale: 1.1, rotate: index % 2 === 0 ? 5 : -5 }}
                        transition={{ type: "spring", stiffness: 300 }}
                        className="glass p-4 rounded-xl shadow-lg border border-primary-purple/20 flex flex-col items-center justify-center w-28 h-28 md:w-40 md:h-40"
                    >
                        <img
                            src={badge.icon?.startsWith('/static/') ? `https://leetcode.com${badge.icon}` : badge.icon}
                            alt={badge.displayName}
                            className="w-16 h-16 md:w-24 md:h-24 object-contain drop-shadow-[0_0_15px_rgba(199,112,240,0.5)]"
                        />
                    </motion.div>
                ))}
            </div>
        </motion.div>
    );
}

export default Badges;

import React from "react";
import { GitHubCalendar } from "react-github-calendar";
import { motion } from "framer-motion";

function Github() {
    return (
        <motion.div
            initial={{ opacity: 0, y: 50 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8 }}
            className="flex flex-col items-center justify-center pb-12 w-full"
        >
            <h2 className="text-3xl md:text-4xl font-bold mb-10 text-center">
                Days I <strong className="text-primary-purple">Code</strong>
            </h2>
            <div className="glass p-6 md:p-8 rounded-xl shadow-2xl overflow-x-auto max-w-full">
                <GitHubCalendar
                    username="AkankshaRaj07"
                    blockSize={15}
                    blockMargin={5}
                    color="#c770f0"
                    fontSize={16}
                />
            </div>
        </motion.div>
    );
}

export default Github;

import React from "react";
import { motion } from "framer-motion";

function Leetcode() {
    return (
        <motion.div
            initial={{ opacity: 0, y: 50 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8, delay: 0.2 }}
            className="flex flex-col items-center justify-center pb-12 w-full"
        >
            <h2 className="text-3xl md:text-4xl font-bold mb-10 text-center">
                <strong className="text-primary-purple">LeetCode</strong> Activity
            </h2>
            <div className="glass p-6 md:p-8 rounded-xl shadow-2xl flex justify-center w-full max-w-[1200px] overflow-hidden">
                {/* 
                  Using JacobLin's LeetCard generator for heatmap extension.
                  We requested a dark theme to match the portfolio aesthetic.
                  Added a specific wrapper to crop out the large top text.
                */}
                <div className="relative w-full overflow-hidden" style={{ height: "200px" }}>
                    <img
                        src="https://leetcard.jacoblin.cool/7IZevn81O2?theme=dark&font=Syne&ext=heatmap"
                        alt="LeetCode Heatmap"
                        className="absolute w-full h-auto object-cover drop-shadow-lg"
                        style={{ bottom: "-15px" }}
                    />
                </div>
            </div>
        </motion.div>
    );
}

export default Leetcode;

import React from "react";
import { CgCPlusPlus } from "react-icons/cg";
import {
    DiJavascript1,
    DiReact,
    DiNodejs,
    DiMongodb,
    DiPython,
    DiGit,
    DiJava,
    DiHtml5,
    DiCss3,
    DiMysql,
} from "react-icons/di";
import { SiExpress, SiFlask } from "react-icons/si";
import { motion } from "framer-motion";

function Techstack() {
    const techs = [
        { icon: <DiJava />, name: "Java" },
        { icon: <DiPython />, name: "Python" },
        { icon: <DiJavascript1 />, name: "JavaScript" },
        { icon: <DiExt name="C++" icon={<CgCPlusPlus />} />, name: "C++" },
        { icon: <DiReact />, name: "ReactJS" },
        { icon: <DiNodejs />, name: "NodeJS" },
        { icon: <SiExpress />, name: "ExpressJS" },
        { icon: <DiMongodb />, name: "MongoDB" },
        { icon: <DiMysql />, name: "MySQL" },
        { icon: <SiFlask />, name: "Flask" },
        { icon: <DiHtml5 />, name: "HTML" },
        { icon: <DiCss3 />, name: "CSS" },
        { icon: <DiGit />, name: "Git" }
    ];

    return (
        <div className="flex flex-wrap justify-center pb-12 gap-4 md:gap-6">
            {techs.map((tech, index) => (
                <TechIconWrapper key={index} name={tech.name}>
                    {tech.icon}
                </TechIconWrapper>
            ))}
        </div>
    );
}

const TechIconWrapper = ({ children, name }) => {
    return (
        <motion.div
            initial={{ opacity: 0, scale: 0.8 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.4 }}
            className="glass flex flex-col items-center justify-center p-4 border border-primary-purple/30 rounded-lg hover:border-primary-purple transition-all duration-300 group relative w-24 h-24 md:w-32 md:h-32 card-hover mb-6"
        >
            <div className="text-4xl md:text-5xl text-gray-300 group-hover:text-primary-purple transition-colors duration-300">
                {name === "C++" ? <CgCPlusPlus /> : children}
            </div>
            <div className="absolute inset-x-0 -bottom-8 opacity-0 group-hover:opacity-100 transition-opacity duration-300 text-center text-sm font-semibold text-primary-purple whitespace-nowrap z-20">
                {name}
            </div>
        </motion.div>
    );
};

// Fallback logic
const DiExt = ({ icon }) => icon;

export default Techstack;

import React from "react";
import {
    SiAndroidstudio,
    SiPostman,
    SiRender,
    SiFigma,
} from "react-icons/si";
import { VscGithubInverted } from "react-icons/vsc";
