export default Toolstack;

import React from "react";
import { motion } from "framer-motion";
import Type from "./Type";
import Tilt from "react-parallax-tilt";
import myImg from "../../assets/pfp.jpeg";

function Home() {
    return (
        <section id="home" className="relative z-10 w-full min-h-[90vh] flex flex-col justify-center items-center py-20">
            <div className="max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8">

                <div className="flex flex-col md:flex-row items-center justify-between gap-12">

                    {/* Text Content */}
                    <motion.div
                        className="w-full md:w-3/5 text-center md:text-left space-y-8"
                        initial={{ opacity: 0, x: -50 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.8 }}
                    >
                        <h1 className="text-4xl md:text-5xl lg:text-6xl font-bold leading-tight">
                            Hi There! <span className="animate-wave inline-block origin-bottom-right">👋🏻</span>
                        </h1>

                        <h1 className="text-4xl md:text-5xl lg:text-6xl font-bold mt-4">
                            I'm <strong className="text-primary-purple">Akanksha Kumari</strong>
                        </h1>

                        <div className="text-2xl md:text-3xl lg:text-4xl mt-8 h-16 md:h-20 flex items-center justify-center md:justify-start">
                            <Type />
                        </div>

                        <p className="text-lg md:text-xl text-gray-300 max-w-2xl mt-6 leading-relaxed">
                            I am a passionate BTech Computer Science student learning and building cool software.
                            I enjoy problem-solving, exploring new technologies, and crafting robust full-stack applications.
                        </p>
                    </motion.div>

                    {/* Hero Image */}
                    <motion.div
                        className="w-full md:w-2/5 flex justify-center mt-12 md:mt-0"
                        initial={{ opacity: 0, x: 50 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.8, delay: 0.2 }}
                    >
                        <Tilt
                            tiltMaxAngleX={15}
                            tiltMaxAngleY={15}
                            perspective={1000}
                            transitionSpeed={1500}
                            scale={1.05}
                            className="w-full max-w-sm"
                        >
                            <div className="relative w-72 h-72 md:w-80 md:h-80 lg:w-96 lg:h-96 mx-auto">
                                <div className="absolute inset-0 bg-primary-purple/20 rounded-full blur-3xl animate-pulse"></div>
                                {/* Fallback avatar icon using lucide, but a photo works better. We use Github Avatar */}
                                <img
                                    src={myImg}
                                    alt="Avatar"
                                    className="rounded-full w-full h-full object-cover scale-90 border-4 border-primary-purple/30 shadow-[0_0_40px_rgba(199,112,240,0.4)] relative z-10"
                                />
                            </div>
                        </Tilt>
                    </motion.div>
                </div>

            </div>
        </section>
    );
}

export default Home;

import React from "react";
import { motion } from "framer-motion";
import { Github, ExternalLink } from "lucide-react";

function ProjectCard({ title, description, ghLink, demoLink, tags }) {
    return (
        <motion.div
            whileHover={{ y: -10 }}
            className="glass rounded-2xl overflow-hidden flex flex-col h-full border border-white/10 hover:border-primary-purple/50 transition-all duration-300 shadow-lg hover:shadow-[0_10px_30px_rgba(199,112,240,0.2)]"
        >
            <div className="p-6 flex flex-col flex-grow">
                <h3 className="text-2xl font-bold text-white mb-3">{title}</h3>

                {/* Tags */}
                <div className="flex flex-wrap gap-2 mb-4">
                    {tags && tags.map((tag, index) => (
                        <span
                            key={index}
                            className="px-2 py-1 text-xs font-semibold bg-primary-purple/20 text-primary-purple rounded-md"
                        >
                            {tag}
                        </span>
                    ))}
                </div>

                <p className="text-gray-300 text-sm flex-grow mb-6 leading-relaxed">
                    {description}
                </p>

                <div className="flex gap-4 mt-auto">
                    {ghLink && (
                        <a
                            href={ghLink}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="flex items-center gap-2 bg-white/5 hover:bg-white/10 text-white py-2 px-4 rounded-lg transition-colors border border-white/10 text-sm font-medium w-full justify-center"
                        >
                            <Github size={18} />
                            GitHub
                        </a>
                    )}
                    {demoLink && (
                        <a
                            href={demoLink}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="flex items-center gap-2 bg-primary-purple hover:bg-primary-purple/80 text-white py-2 px-4 rounded-lg transition-colors text-sm font-medium w-full justify-center"
                        >
                            <ExternalLink size={18} />
                            Demo
                        </a>
                    )}
                </div>
            </div>
        </motion.div>
    );
}

export default ProjectCard;

